package com.google.gson;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

import org.junit.jupiter.api.Test;

class JsonElementTest {

  // Concrete subclass to instantiate abstract JsonElement
  static class TestJsonElement extends JsonElement {
    @Override
    public JsonElement deepCopy() {
      return this;
    }
  }

  @Test
  void getAsByte_shouldThrowUnsupportedOperationException_withClassSimpleName() {
    JsonElement element = new TestJsonElement();

    UnsupportedOperationException exception = assertThrows(
        UnsupportedOperationException.class,
        element::getAsByte);

    assertEquals("TestJsonElement", exception.getMessage());
  }
}
